     1→/**
     2→ * K3RN.LABS — POST /api/expert-chat
     3→ * Chat expert contextuel via Claude API avec streaming SSE
     4→ */
     5→
     6→import Anthropic from "@anthropic-ai/sdk";
     7→
     8→const anthropic = new Anthropic({
     9→    apiKey: process.env.ANTHROPIC_API_KEY,
    10→});
    11→
    12→const CHAT_MODEL = process.env.EXPERT_CHAT_MODEL || "claude-sonnet-4-20250514";
    13→
    14→interface ChatMessage {
    15→    role: "user" | "assistant";
    16→    content: string;
    17→}
    18→
    19→interface ChatRequest {
    20→    messages: ChatMessage[];
    21→    projectContext: {
    22→        title: string;
    23→        description: string;
    24→        globalScore: number;
    25→        recommendation: string;
    26→        confidenceLevel: string;
    27→        axes: Array<{ label: string; score: number; justification?: string }>;
    28→        synthesis: string;
    29→        risks: string[];
    30→        levers?: Array<{ axis: string; action: string; expected_impact: string }>;
    31→    };
    32→    labType: "discovery" | "structuration" | "validation";
    33→    language: string;
    34→}
    35→
    36→function buildSystemPrompt(req: ChatRequest): string {
    37→    const { projectContext, labType, language } = req;
    38→    const lang = language === "FR" ? "français" : language === "ES" ? "español" : "English";
    39→
    40→    const projectBlock = `
    41→## Projet analysé
    42→- **Titre** : ${projectContext.title}
    43→- **Description** : ${projectContext.description}
    44→- **Score global** : ${projectContext.globalScore}/100
    45→- **Recommandation** : ${projectContext.recommendation}
    46→- **Confiance** : ${projectContext.confidenceLevel}
    47→
    48→### Axes d'analyse
    49→${projectContext.axes.map((a) => `- **${a.label}** : ${a.score}/100${a.justification ? ` — ${a.justification}` : ""}`).join("\n")}
    50→
    51→### Synthèse
    52→${projectContext.synthesis}
    53→
    54→### Risques identifiés
    55→${projectContext.risks.length > 0 ? projectContext.risks.map((r) => `- ${r}`).join("\n") : "Aucun risque majeur identifié."}
    56→${projectContext.levers && projectContext.levers.length > 0
    57→            ? `\n### Leviers d'action\n${projectContext.levers.map((l) => `- [${l.expected_impact}] ${l.action} (axe: ${l.axis})`).join("\n")}`
    58→            : ""
    59→        }`;
    60→
    61→    if (labType === "discovery") {
    62→        return `Tu es **Ava**, experte en Discovery et validation d'idées chez K3RN.LABS.
    63→
    64→## Ta personnalité
    65→- Socratique : tu poses des questions qui forcent la réflexion profonde
    66→- Challengeuse : tu identifies les failles et angles morts sans complaisance
    67→- Bienveillante mais directe : tu veux aider l'entrepreneur à voir clair
    68→
    69→## Ton rôle dans le Lab Discovery
    70→- Challenger les hypothèses non validées
    71→- Mettre en lumière les axes faibles (score < 50) et les risques
    72→- Poser des questions ouvertes qui poussent à l'investigation terrain
    73→- Suggérer des expériences de validation rapides (interviews, landing pages, smoke tests)
    74→- Ne JAMAIS donner de fausses assurances — si le projet a des failles, les nommer
    75→
    76→## Règles
    77→- Réponds en ${lang}
    78→- Sois concise (2-4 paragraphes max sauf si la question demande plus)
    79→- Utilise le contexte projet ci-dessous pour personnaliser chaque réponse
    80→- Si l'utilisateur sort du sujet, ramène-le au projet
    81→
    82→${projectBlock}`;
    83→    }
    84→
    85→    if (labType === "validation") {
    86→        return `Tu es **Sarah**, Market Validator experte chez k3rn.labs.
    87→
    88→## IDENTITÉ
    89→**Spécialisation :** Market Analysis
    90→**Rôle :** Valider la taille du marché, identifier les concurrents et analyser les tendances.
    91→**Persona :** Stratège, orientée données, experte en tendances.
    92→
    93→## MISSION
    94→Tu as été mandatée par le XO pour analyser le marché du projet.
    95→
    96→## MÉTHODOLOGIE
    97→Tu vas guider l'utilisateur à travers une conversation structurée pour :
    98→1. Valider la taille du marché (TAM/SAM/SOM)
    99→2. Identifier les concurrents
   100→3. Analyser les tendances
   101→
   102→## OUTILS EXTÉRIEURS
   103→Tu as accès à des outils pour enrichir ton analyse. Pour les utiliser, génère une commande spécifique dans ta réponse :
   104→1. **Recherche Reddit** : Commande : \`[REDDIT_SEARCH: votre requête]\`
   105→2. **Google Trends** : Commande : \`[GOOGLE_TRENDS: votre mot clé]\`
   106→Utilise ces outils au début de la conversation.
   107→
   108→## STRUCTURE DE LA CONVERSATION
   109→**Tour 1 : Diagnostic initial**
   110→Commence par évaluer la taille du marché. Demande qui sont les clients cibles.
   111→
   112→**Tour 2-3 : Approfondissement**
   113→Pose des questions sur le TAM, SAM, SOM et les concurrents.
   114→
   115→**Tour 4 : Analyse concurrentielle**
   116→Demande des précisions sur la différenciation.
   117→
   118→**Tour 5 : Synthèse**
   119→Synthétise les points clés.
   120→
   121→## Règles
   122→- Réponds en ${lang}
   123→- Sois Professionnel et data-driven.
   124→- Pose des questions précises sur les chiffres.
   125→
   126→${projectBlock}`;
   127→    }
   128→
   129→    return `Tu es **Marcus**, expert en Structuration et stratégie business chez K3RN.LABS.
   130→
   131→## Ta personnalité
   132→- Pragmatique : tu penses en frameworks actionnables (BMC, Lean Canvas, OKR)
   133→- Stratège : tu vois les leviers de croissance et les quick wins
   134→- Orienté action : chaque conseil doit aboutir à un next step concret
   135→
   136→## Ton rôle dans le Lab Structuration
   137→- Aider à construire le Business Model Canvas
   138→- Transformer les leviers d'action en plan concret avec milestones
   139→- Capitaliser sur les forces (axes ≥ 70) pour définir l'avantage concurrentiel
   140→- Proposer des métriques clés (KPI) pour chaque milestone
   141→- Structurer la roadmap : MVP → Premiers Users → Revenue → Scale
   142→
   143→## Règles
   144→- Réponds en ${lang}
   145→- Sois concis et actionnable (2-4 paragraphes max sauf si la question demande plus)
   146→- Utilise le contexte projet ci-dessous pour personnaliser chaque réponse
   147→- Si l'utilisateur sort du sujet, ramène-le à la structuration
   148→
   149→${projectBlock}`;
   150→}
   151→
   152→export async function POST(req: Request) {
   153→    try {
   154→        const body: ChatRequest = await req.json();
   155→
   156→        if (!body.messages || !Array.isArray(body.messages) || body.messages.length === 0) {
   157→            return new Response(JSON.stringify({ error: "messages required" }), {
   158→                status: 400,
   159→                headers: { "Content-Type": "application/json" },
   160→            });
   161→        }
   162→
   163→        const systemPrompt = buildSystemPrompt(body);
   164→
   165→        const stream = anthropic.messages.stream({
   166→            model: CHAT_MODEL,
   167→            max_tokens: 1024,
   168→            temperature: 0.7,
   169→            system: systemPrompt,
   170→            messages: body.messages.map((m) => ({
   171→                role: m.role,
   172→                content: m.content,
   173→            })),
   174→        });
   175→
   176→        const encoder = new TextEncoder();
   177→
   178→        const readable = new ReadableStream({
   179→            async start(controller) {
   180→                try {
   181→                    for await (const event of stream) {
   182→                        if (
   183→                            event.type === "content_block_delta" &&
   184→                            event.delta.type === "text_delta"
   185→                        ) {
   186→                            const data = JSON.stringify({ text: event.delta.text });
   187→                            controller.enqueue(encoder.encode(`data: ${data}\n\n`));
   188→                        }
   189→                    }
   190→                    controller.enqueue(encoder.encode("data: [DONE]\n\n"));
   191→                    controller.close();
   192→                } catch (error: any) {
   193→                    const errorData = JSON.stringify({
   194→                        error: error.status === 429 ? "rate_limited" : "stream_error",
   195→                        message: error.message,
   196→                    });
   197→                    controller.enqueue(encoder.encode(`data: ${errorData}\n\n`));
   198→                    controller.close();
   199→                }
   200→            },
   201→        });
   202→
   203→        return new Response(readable, {
   204→            headers: {
   205→                "Content-Type": "text/event-stream",
   206→                "Cache-Control": "no-cache",
   207→                Connection: "keep-alive",
   208→            },
   209→        });
   210→    } catch (error: any) {
   211→        if (error.status === 429) {
   212→            return new Response(
   213→                JSON.stringify({ error: "rate_limited", message: "Too many requests" }),
   214→                { status: 429, headers: { "Content-Type": "application/json" } }
   215→            );
   216→        }
   217→        return new Response(
   218→            JSON.stringify({ error: "internal", message: error.message }),
   219→            { status: 500, headers: { "Content-Type": "application/json" } }
   220→        );
   221→    }
   222→}
   223→

