     1→/**
     2→ * K3RN.LABS — POST /api/enrichment
     3→ *
     4→ * Deux modes d'opération :
     5→ *
     6→ * MODE 1 — Générer les questions (body.action = "generate")
     7→ *   Input: analysis + scores + decision
     8→ *   Output: questions guidées (DETERMINISTIC via enrichment-trigger)
     9→ *
    10→ * MODE 2 — Soumettre les réponses et recalculer (body.action = "submit")
    11→ *   Input: enrichment_id + responses
    12→ *   Output: scores recalculés + nouvelle décision (via score-recalculator)
    13→ */
    14→
    15→import { NextResponse } from 'next/server';
    16→import { z } from 'zod';
    17→import {
    18→  shouldTriggerEnrichment,
    19→  generateEnrichmentQuestions,
    20→  AnalysisResult
    21→} from '@/lib/analysis/enrichment-trigger';
    22→import { recalculateScores } from '@/lib/analysis/score-recalculator';
    23→import { enrichmentResponseSchema } from '@/lib/analysis/validators';
    24→import { SCHEMA_VERSION } from '@/lib/analysis/constants';
    25→import type { AnalysisAxes, ApiError, AnalysisScores, AnalysisDecision } from '@/lib/analysis/types';
    26→
    27→// ─── Request schemas ────────────────────────────────────────────
    28→
    29→const axisAnalysisSchema = z.object({
    30→  score: z.number().int().min(0).max(100),
    31→  justification: z.string().min(20).max(300),
    32→  blocking_gap: z.boolean(),
    33→});
    34→
    35→const generateRequestSchema = z.object({
    36→  action: z.literal('generate'),
    37→  idea_id: z.string().min(1),
    38→  idea_summary: z.string().min(10),
    39→  analysis: z.object({
    40→    problem: axisAnalysisSchema,
    41→    market: axisAnalysisSchema,
    42→    differentiation: axisAnalysisSchema,
    43→    feasibility: axisAnalysisSchema,
    44→    business: axisAnalysisSchema,
    45→    founder_fit: axisAnalysisSchema,
    46→  }),
    47→  scores: z.object({
    48→    global_score: z.number().int().min(0).max(100),
    49→  }),
    50→  decision: z.object({
    51→    recommendation: z.enum(['GO', 'EXPLORE', 'PARK', 'KILL']),
    52→    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
    53→  }),
    54→});
    55→
    56→const submitRequestSchema = z.object({
    57→  action: z.literal('submit'),
    58→  enrichment_id: z.string().min(1),
    59→  idea_id: z.string().min(1),
    60→  analysis: z.object({
    61→    problem: axisAnalysisSchema,
    62→    market: axisAnalysisSchema,
    63→    differentiation: axisAnalysisSchema,
    64→    feasibility: axisAnalysisSchema,
    65→    business: axisAnalysisSchema,
    66→    founder_fit: axisAnalysisSchema,
    67→  }),
    68→  scores: z.object({
    69→    global_score: z.number().int().min(0).max(100),
    70→  }),
    71→  decision: z.object({
    72→    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
    73→  }),
    74→  questions: z.array(z.object({
    75→    question_id: z.string(),
    76→    axis: z.enum(['problem', 'market', 'differentiation', 'feasibility', 'business', 'founder_fit']),
    77→    options: z.array(z.object({
    78→      id: z.string(),
    79→      score_adjustment: z.number(),
    80→    })),
    81→  })),
    82→  responses: z.array(enrichmentResponseSchema),
    83→});
    84→
    85→// ═══════════════════════════════════════════════════════════════════
    86→// POST /api/enrichment
    87→// ═══════════════════════════════════════════════════════════════════
    88→
    89→export async function POST(req: Request) {
    90→  try {
    91→    let body: unknown;
    92→    try {
    93→      body = await req.json();
    94→    } catch {
    95→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Request body is not valid JSON');
    96→    }
    97→
    98→    // Determine action
    99→    const actionCheck = z.object({ action: z.enum(['generate', 'submit']) }).safeParse(body);
   100→    if (!actionCheck.success) {
   101→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Missing or invalid "action" field. Must be "generate" or "submit".');
   102→    }
   103→
   104→    if (actionCheck.data.action === 'generate') {
   105→      return handleGenerate(body);
   106→    } else {
   107→      return handleSubmit(body);
   108→    }
   109→  } catch (error: unknown) {
   110→    const err = error as Error;
   111→    console.error('Unexpected enrichment error:', err);
   112→    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
   113→  }
   114→}
   115→
   116→// ═══════════════════════════════════════════════════════════════════
   117→// MODE 1 : GENERATE QUESTIONS
   118→// ═══════════════════════════════════════════════════════════════════
   119→
   120→async function handleGenerate(body: unknown) {
   121→  const validation = generateRequestSchema.safeParse(body);
   122→  if (!validation.success) {
   123→    return errorResponse(400, 'INPUT_SCHEMA_INVALID', validation.error.issues.map((i) => `${i.path.join('.')} ${i.message}`).join('; '));
   124→  }
   125→
   126→  const data = validation.data;
   127→
   128→  // Construct AnalysisResult object compatible with shared logic
   129→  const analysisResult: AnalysisResult = {
   130→    analysis: data.analysis as AnalysisAxes,
   131→    scores: {
   132→      global_score: data.scores.global_score,
   133→      weights: {} // weights will be defaulted in logic if missing
   134→    },
   135→    decision: {
   136→      ...data.decision,
   137→      summary: '' // missing in check but not strictly needed for trigger
   138→    } as any
   139→  };
   140→
   141→  // ─── Check enrichment is actually needed ──────────────────────
   142→  const isRequired = shouldTriggerEnrichment(analysisResult);
   143→
   144→  if (!isRequired) {
   145→    return NextResponse.json({
   146→      enrichment_id: null,
   147→      required: false,
   148→      message: 'No enrichment triggers detected',
   149→      trigger_axes: [],
   150→      questions: [],
   151→    });
   152→  }
   153→
   154→  // ─── Generate Questions (Deterministic) ───────────────────────
   155→  const questions = generateEnrichmentQuestions(analysisResult);
   156→
   157→  if (questions.length === 0) {
   158→    return NextResponse.json({
   159→      enrichment_id: null,
   160→      required: false,
   161→      message: 'No targeted questions found for weak axes',
   162→      trigger_axes: [],
   163→      questions: [],
   164→    });
   165→  }
   166→
   167→  const enrichmentId = crypto.randomUUID();
   168→  const triggerAxes = Array.from(new Set(questions.map(q => q.axis)));
   169→
   170→  return NextResponse.json({
   171→    enrichment_id: enrichmentId,
   172→    idea_id: data.idea_id,
   173→    required: true,
   174→    timestamp: new Date().toISOString(),
   175→    trigger_axes: triggerAxes,
   176→    questions: questions,
   177→    max_questions: 5,
   178→  });
   179→}
   180→
   181→// ═══════════════════════════════════════════════════════════════════
   182→// MODE 2 : SUBMIT RESPONSES & RECALCULATE
   183→// ═══════════════════════════════════════════════════════════════════
   184→
   185→async function handleSubmit(body: unknown) {
   186→  const validation = submitRequestSchema.safeParse(body);
   187→  if (!validation.success) {
   188→    // Validation might fail if we are lax on weights in input but strict in schema
   189→    // The schema defines scores object limited to global_score.
   190→    // But logic might need more.
   191→    return errorResponse(400, 'INPUT_SCHEMA_INVALID', validation.error.issues.map((i) => `${i.path.join('.')} ${i.message}`).join('; '));
   192→  }
   193→
   194→  const data = validation.data;
   195→
   196→  // Prepare input for recalculator
   197→  const partialAnalysis = {
   198→    analysis: data.analysis as AnalysisAxes,
   199→    scores: {
   200→      global_score: data.scores.global_score,
   201→      weights: {}
   202→    },
   203→    decision: {
   204→      confidence_level: data.decision.confidence_level,
   205→      recommendation: 'EXPLORE', // placeholder, will be recalculated
   206→      summary: ''
   207→    } as AnalysisDecision
   208→  };
   209→
   210→  // ─── Recalculate ──────────────────────────────────────────────
   211→  const result = recalculateScores(partialAnalysis, data.responses);
   212→
   213→  return NextResponse.json({
   214→    enrichment_id: data.enrichment_id,
   215→    idea_id: data.idea_id,
   216→    timestamp: new Date().toISOString(),
   217→    scores_before: result.scores_before,
   218→    scores_after: result.scores_after,
   219→    decision_before: result.decision_before,
   220→    decision_after: result.decision_after,
   221→    adjustments: result.adjustments,
   222→    updated_analysis: result.updated_analysis,
   223→    updated_scores: result.updated_scores,
   224→  });
   225→}
   226→
   227→// ═══════════════════════════════════════════════════════════════════
   228→// ERROR HELPER
   229→// ═══════════════════════════════════════════════════════════════════
   230→
   231→function errorResponse(status: number, code: string, message: string): NextResponse<ApiError> {
   232→  return NextResponse.json(
   233→    {
   234→      error: {
   235→        code,
   236→        message,
   237→        details: { schema_version: SCHEMA_VERSION },
   238→      },
   239→    },
   240→    { status }
   241→  );
   242→}
   243→

