     1→import { NextRequest, NextResponse } from 'next/server';
     2→import OpenAI from 'openai';
     3→import { SYSTEM_PROMPT } from '@/lib/logo-generator/prompts';
     4→
     5→const openai = new OpenAI({
     6→    apiKey: process.env.OPENAI_API_KEY,
     7→});
     8→
     9→// In-memory conversation storage
    10→const conversations = new Map<string, Array<{ role: string; content: string }>>();
    11→
    12→export async function POST(request: NextRequest) {
    13→    try {
    14→        const formData = await request.formData();
    15→        const conversationId = formData.get('conversationId') as string;
    16→        const message = formData.get('message') as string;
    17→        const linksJson = formData.get('links') as string;
    18→        const links = linksJson ? JSON.parse(linksJson) : [];
    19→
    20→        // Get or initialize conversation history
    21→        let history = conversations.get(conversationId) || [];
    22→
    23→        // Build user message
    24→        let userContent = message;
    25→        if (links.length > 0) {
    26→            userContent += `\n\nLiens de référence: ${links.join(', ')}`;
    27→        }
    28→
    29→        history.push({
    30→            role: 'user',
    31→            content: userContent,
    32→        });
    33→
    34→        // Determine if we should generate a logo or ask questions
    35→        const shouldGenerateLogo = history.length === 1; // First user message
    36→
    37→        let systemMessage = SYSTEM_PROMPT;
    38→        if (shouldGenerateLogo) {
    39→            systemMessage += `\n\nGenerate a logo based on the user's description. Return a JSON object with:
    40→{
    41→  "logoHtml": "<svg>...</svg>",
    42→  "message": "Brief explanation of the design",
    43→  "options": ["Style option 1", "Style option 2", "Style option 3", "Style option 4"]
    44→}
    45→
    46→The SVG should be complete, valid, and visually appealing. Use modern design principles.`;
    47→        } else {
    48→            systemMessage += `\n\nContinue the conversation naturally. If appropriate, ask clarifying questions with 3-4 options. Return JSON:
    49→{
    50→  "message": "Your response",
    51→  "options": ["Option 1", "Option 2", "Option 3"] // optional
    52→}`;
    53→        }
    54→
    55→        // Call OpenAI
    56→        const completion = await openai.chat.completions.create({
    57→            model: 'gpt-4o',
    58→            messages: [
    59→                {
    60→                    role: 'system',
    61→                    content: systemMessage,
    62→                },
    63→                ...history.map((msg) => ({
    64→                    role: msg.role as 'user' | 'assistant',
    65→                    content: msg.content,
    66→                })),
    67→            ],
    68→            response_format: { type: 'json_object' },
    69→            temperature: 0.8,
    70→        });
    71→
    72→        const response = JSON.parse(completion.choices[0].message.content || '{}');
    73→
    74→        // Update conversation history
    75→        history.push({
    76→            role: 'assistant',
    77→            content: response.message,
    78→        });
    79→        conversations.set(conversationId, history);
    80→
    81→        return NextResponse.json({
    82→            message: response.message,
    83→            options: response.options,
    84→            logoHtml: response.logoHtml,
    85→        });
    86→    } catch (error) {
    87→        console.error('Error in chat:', error);
    88→        return NextResponse.json(
    89→            { error: 'Failed to process message' },
    90→            { status: 500 }
    91→        );
    92→    }
    93→}
