     5→import { getLabDefinition, LAB_1_DISCOVERY, LAB_2_STRUCTURATION } from './definitions'
     6→import { WorkflowStatus } from '@prisma/client'
     7→
     8→export class WorkflowService {
     9→
    10→    static async getActiveWorkflow(dossierId: string) {
    11→        return prisma.labWorkflow.findFirst({
    12→            where: {
    13→                dossierId,
    14→                status: 'IN_PROGRESS'
    15→            },
    16→            orderBy: { createdAt: 'desc' },
    17→            include: {
    18→                lab: true
    19→            }
    20→        })
    21→    }
    22→
    23→    static async startWorkflow(dossierId: string, labNumber: number) {
    24→        // 1. Check prerequisites
    25→        const dossier = await prisma.dossier.findUnique({ where: { id: dossierId } })
    26→        if (!dossier) throw new Error('Dossier not found')
    27→
    28→        const definition = getLabDefinition(labNumber)
    29→
    30→        // Check previous lab completion for Lab 2
    31→        if (labNumber === 2) {
    32→            // Gate Check: Score >= 50
    33→            const score = dossier.globalScore
    34→            if (score < 50) {
    35→                throw new Error(`Score insuffisant (${score}/50) pour accéder au Lab 2`)
    36→            }
    37→
    38→            // Check Lab 1 completion
    39→            const lab1Workflow = await prisma.labWorkflow.findFirst({
    40→                where: {
    41→                    dossierId,
    42→                    labId: {
    43→                        // Assuming we can find Lab 1 by some means, or check completed status
    44→                        // Ideally we check if a workflow for Lab 1 is COMPLETED
    45→                    },
    46→                    status: 'COMPLETED'
    47→                }
    48→            })
    49→
    50→            // For MVP, we might skip strict checking if we rely just on Score for now
    51→            // or check if 'ANALYZED' state allows entry.
    52→        }
    53→
    54→        // 2. Find Lab entity
    55→        // We assume Labs are seeded. If not, we might need to find by name or order.
    56→        const lab = await prisma.lab.findUnique({ where: { order: labNumber } })
    57→        if (!lab) throw new Error('Lab configuration not found in DB')
    58→
    59→        // 3. Create Workflow
    60→        return prisma.labWorkflow.create({
    61→            data: {
    62→                dossierId,
    63→                labId: lab.id,
    64→                currentStep: 0,
    65→                totalSteps: definition.steps.length,
    66→                status: 'IN_PROGRESS',
    67→                completedSteps: []
    68→            }
    69→        })
    70→    }
    71→
    72→    static async advanceStep(workflowId: string) {
    73→        const workflow = await prisma.labWorkflow.findUnique({ where: { id: workflowId } })
    74→        if (!workflow) throw new Error('Workflow not found')
    75→
    76→        const labNumber = 1 // TODO: Fetch from included relation
    77→        // We need to fetch relation to know which definition to use
    78→        // For MVP, let's assume we can derive it or pass it.
    79→        // Better: Fetch workflow with Lab
    80→        const workflowWithLab = await prisma.labWorkflow.findUnique({
    81→            where: { id: workflowId },
    82→            include: { lab: true }
    83→        })
    84→
    85→        if (!workflowWithLab) throw new Error('Workflow not found')
    86→
    87→        const definition = getLabDefinition(workflowWithLab.lab.order)
    88→
    89→        if (workflow.currentStep >= definition.steps.length - 1) {
    90→            // Already at end, mark completed
    91→            return prisma.labWorkflow.update({
    92→                where: { id: workflowId },
    93→                data: {
    94→                    status: 'COMPLETED',
    95→                    completedAt: new Date()
    96→                }
    97→            })
    98→        }
    99→
   100→        const nextStepIndex = workflow.currentStep + 1
   101→
   102→        // Logic for Gate Check Step (if current was Gate)
   103→        // If next step is Gate Check, we verify here? 
   104→        // Usually we verify BEFORE entering next step or completing current.
   105→
   106→        return prisma.labWorkflow.update({
   107→            where: { id: workflowId },
   108→            data: {
   109→                currentStep: nextStepIndex
   110→            }
   111→        })
   112→    }
   113→
   114→    static async checkGate(dossierId: string, targetLabNumber: number): Promise<{ allowed: boolean, reason?: string }> {
   115→        const dossier = await prisma.dossier.findUnique({ where: { id: dossierId } })
   116→        if (!dossier) return { allowed: false, reason: 'Dossier not found' }
   117→
   118→        if (targetLabNumber === 2) {
   119→            if (dossier.globalScore < 50) return { allowed: false, reason: 'Score global insuffisant (< 50/100)' }
   120→
   121→            // Optional: Check if Lab 1 is done
   122→            // const lab1Done = ...
   123→        }
   124→
   125→        return { allowed: true }
   126→    }
   127→}
